sql:
SELECT MIN(percent_deaths) AS min_percent_deaths
FROM mortality_stats
WHERE year = 1 AND week = 1;

SELECT SUM(pneumonia_deaths + influenza_deaths) AS total_influenza_pneumonia_deaths
   FROM mortality_stats
   WHERE year = 2013 AND week = 2;

SELECT AVG(percent_deaths) AS average_percent_deaths
FROM mortality_stats
WHERE year = 2013;

SELECT AVG(expected_rate) AS average_expected_rate
FROM expected_rates
WHERE rate_type = 'Regional Average';

SELECT year, week
FROM mortality_stats
WHERE percent_deaths > (SELECT threshold_value FROM thresholds WHERE threshold_id = 1);

SELECT percent_deaths
FROM mortality_stats
WHERE year = 2013 AND week = 1;

SELECT year, percent_deaths
FROM mortality_stats
WHERE threshold = 8.49104 AND percent_deaths > threshold;

SELECT AVG(percent_deaths) AS average_percent_deaths
FROM mortality_stats
WHERE data_quality_score >= 7;

SELECT AVG(percent_deaths) AS avg_percent_deaths
FROM mortality_stats
WHERE year IN (SELECT year FROM years);

SELECT year, AVG(percent_deaths) AS avg_percent_deaths
FROM mortality_stats
GROUP BY year;

SELECT DISTINCT year
FROM mortality_stats
ORDER BY year ASC;

SELECT year, expected_rate
FROM expected_rates
WHERE rate_type = 'Regional Average' AND confidence_interval < 0.2;

SELECT year, AVG(expected_rate) AS avg_expected_rate
FROM expected_rates
GROUP BY year;

SELECT percent_deaths
FROM mortality_stats
WHERE threshold > (SELECT threshold_value FROM thresholds WHERE threshold_type = 'National Threshold');

SELECT year, week
FROM mortality_stats
ORDER BY year DESC, week DESC;

external_knowledge:
- National mortality rate threshold refers to the value above which mortality rates are considered significantly high; 
- Deviation is calculated as the actual mortality rate minus the expected mortality rate; 
- Weeks are ranked based on the magnitude of their deviations.
